async (params, browser) => {
  // Open Craigslist city search
  await browser.open(`https://${params.city}.craigslist.org/search/sss?query=${params.query}`)

  // Wait for page
  await browser.waitForSelector('.cl-search-result, .result-row, .cl-static-search-result, body', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract data
  const result = await browser.evaluate(`const results = []; document.querySelectorAll('.cl-search-result, .result-row, .cl-static-search-result').forEach((el, i) => { if (i < 20) { const titleEl = el.querySelector('a.posting-title, a.result-title, .titlestring, a.cl-app-anchor'); const priceEl = el.querySelector('.priceinfo, .result-price'); results.push({ title: titleEl?.textContent?.trim() || '', url: titleEl?.href || '', price: priceEl?.textContent?.trim() || '' }); } }); return { city: '' + params.city + '', query: '' + params.query + '', result_count: results.length, results };`)

  return result
}
